import { supabase } from '../../lib/supabase';

/**
 * Migre les produits de `boutiqueData` vers une table Supabase.
 * - Garde tous les champs essentiels et ajoute `external_id` pour éviter les doublons.
 * - Upsert par lots (option `onConflict: 'external_id'`).
 * @param {{table?:string,batchSize?:number}} options
 * @returns {{inserted:number,updated:number,errors:Array}} résumé
 */
export async function migrateToSupabase({ table = 'products', batchSize = 100 } = {}) {
  if (!supabase) throw new Error('Supabase client introuvable. Vérifie src/lib/supabase.js');

  const items = [];
  for (const category of boutiqueData) {
    const categoryId = category.id ?? null;
    const categoryName = category.name ?? null;
    if (!Array.isArray(category.subcategories)) continue;
    for (const sub of category.subcategories) {
      const subId = sub.id ?? null;
      const subName = sub.name ?? null;
      if (!Array.isArray(sub.products)) continue;
      for (const p of sub.products) {
        const external_id = `${categoryId}-${subId}-${p.id}`;
        items.push({
          external_id,
          name: p.name ?? null,
          price: p.price ?? null,
          rating: p.rating ?? null,
          featured: !!p.featured,
          category_id: categoryId,
          category_name: categoryName,
          subcategory_id: subId,
          subcategory_name: subName,
          description: p.description ?? null,
          image: p.imageUrl ?? null,
          meta: { originalProductId: p.id, raw: p }
        });
      }
    }
  }

  const chunks = [];
  for (let i = 0; i < items.length; i += batchSize) chunks.push(items.slice(i, i + batchSize));

  const result = { inserted: 0, updated: 0, errors: [] };

  for (const chunk of chunks) {
    const { data, error } = await supabase.from(table).upsert(chunk, { onConflict: 'external_id' });
    if (error) {
      result.errors.push(error.message || error);
    } else if (Array.isArray(data)) {
      // supabase upsert retourne les lignes insérées/updated
      result.inserted += data.length;
    }
  }

  return result;
}

export default boutiqueData;